Drupal.behaviors.textCopyButton={attach(t){t.querySelectorAll(".text-copy-button__button:not([data-text-copy-init])").forEach((t=>{t.setAttribute("data-text-copy-init","");const e=t.textContent.trim();t.addEventListener("click",(t=>{const o=t.target.closest(".text-copy-button__button");if(!o||!navigator.clipboard)return;const n=o.closest(".text-copy-button");if(!n)return;const c=n.querySelector(".pre-text__text");if(!c)return;const r=c.textContent.trim();navigator.clipboard.writeText(r).then((()=>{const t=new CustomEvent("text-copy-button:copied",{bubbles:!0,cancelable:!0,detail:{text:r,button:o}});o.dispatchEvent(t)&&(o.textContent="Copied to clipboard",setTimeout((()=>{o.textContent=e}),1700))})).catch((()=>{o.textContent="(error)"}))}))}))}};